// 🌟 Inside your src/ExpertDashboard.js Component code setup:
// Swap out your old [username, setUsername] state with this:
const [email, setEmail] = useState('');
const [password, setPassword] = useState('');

// Update the login fetch request payload mapping key strings:
const handleLoginSubmit = async (e) => {
  e.preventDefault();
  try {
    const response = await fetch('http://localhost/farmer-portal-backend/expert_login.php', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email, password }) // 🌟 Sending email field payload
    });
    const result = await response.json();

    if (result.status === 'success') {
      setExpertProfile({ name: result.expert_name, dept: result.department });
      setIsLoggedIn(true);
      fetchPending(); 
    } else {
      alert("Access Denied: " + result.message);
    }
  } catch (err) {
    alert("Failed to connect to authentication script server.");
  }
};

// Update your input text rendering layout markup fields:
/* Replace the old username text input with this email input block box inside your JSX code: */
<div>
  <label style={{ display: 'block', fontWeight: 'bold', fontSize: '0.9rem', marginBottom: '4px' }}>Center Email Address:</label>
  <input 
    type="email" 
    placeholder="e.g., mushroom.center@gbpuat.ac.in"
    value={email}
    onChange={(e) => setEmail(e.target.value)}
    style={{ width: '100%', padding: '10px', border: '1px solid #ccc', borderRadius: '4px', boxSizing: 'border-box' }}
    required
  />
</div>
